// Models/RapidAPIEndpoint.swift\nimport Foundation\nimport SwiftData\n\n@Model\nfinal class RapidAPIEndpoint {\n    @Attribute(.unique) var id: String\n    var name: String\n    var description: String\n    var category: String\n    var pricingTier: String\n    var rating: Double\n    var subscribers: Int\n    var pricePerRequest: Double?\n    var createdAt: Date\n\n    init(id: String, name: String, description: String, category: String, pricingTier: String, rating: Double, subscribers: Int, pricePerRequest: Double? = nil) {\n        self.id = id\n        self.name = name\n        self.description = description\n        self.category = category\n        self.pricingTier = pricingTier\n        self.rating = rating\n        self.subscribers = subscribers\n        self.pricePerRequest = pricePerRequest\n        self.createdAt = Date()\n    }\n}\n